import torch
from torch import Tensor


# в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
#  Dirac Gamma Matrices вЂ” Chiral (Weyl) rep
# в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

def pauli_matrices() -> tuple[Tensor, Tensor, Tensor]:
    """Return the three Pauli matrices as complex64 tensors (2Г—2)."""
    Пѓ_x = torch.tensor([[0, 1], [1, 0]], dtype=torch.complex64)
    Пѓ_y = torch.tensor([[0, -1j], [1j, 0]], dtype=torch.complex64)
    Пѓ_z = torch.tensor([[1, 0], [0, -1]], dtype=torch.complex64)
    return Пѓ_x, Пѓ_y, Пѓ_z


def gamma_matrices(metric_sign: str = '+---') -> tuple[Tensor, ...]:
    """
    Return the four Dirac gamma matrices in the Weyl (chiral) representation.

    Args:
        metric_sign: Metric signature convention вЂ” '+---' for particle physics,
                     '-+++' for GR. This affects Оі^0 sign convention.

    Returns:
        Tuple of 4 gamma matrices, each (4, 4) complex64.

    Weyl representation:
        Оі^0 = [[0,  I],
               [I,  0]]

        Оі^i = [[0,   Пѓ^i],
               [-Пѓ^i, 0]]
    """
    I2 = torch.eye(2, dtype=torch.complex64)
    O2 = torch.zeros(2, 2, dtype=torch.complex64)
    Пѓ_x, Пѓ_y, Пѓ_z = pauli_matrices()

    def _block(top_left, top_right, bottom_left, bottom_right):
        top = torch.cat([top_left, top_right], dim=1)
        bottom = torch.cat([bottom_left, bottom_right], dim=1)
        return torch.cat([top, bottom], dim=0)

    Оі0 = _block(O2, I2, I2, O2)
    Оі1 = _block(O2, Пѓ_x, -Пѓ_x, O2)
    Оі2 = _block(O2, Пѓ_y, -Пѓ_y, O2)
    Оі3 = _block(O2, Пѓ_z, -Пѓ_z, O2)

    if metric_sign == '-+++':
        Оі0 = -Оі0

    return Оі0, Оі1, Оі2, Оі3


def gamma5() -> Tensor:
    """
    Return the ОівЃµ matrix in the Weyl representation.

        ОівЃµ = [[-I, 0],
              [ 0, I]]
    """
    I2 = torch.eye(2, dtype=torch.complex64)
    O2 = torch.zeros(2, 2, dtype=torch.complex64)
    top = torch.cat([-I2, O2], dim=1)
    bottom = torch.cat([O2, I2], dim=1)
    return torch.cat([top, bottom], dim=0)


def clifford_anticommutator(ОіОј: Tensor, ОіОЅ: Tensor) -> Tensor:
    """
    Compute {Оі^Ој, Оі^ОЅ} = Оі^Ој Оі^ОЅ + Оі^ОЅ Оі^Ој.

    Returns a (4, 4) complex tensor.
    For ОіОј and ОіОЅ from the standard gamma matrices, this should equal 2 О·^ОјОЅ I_4.
    """
    return ОіОј @ ОіОЅ + ОіОЅ @ ОіОј


def verify_clifford_algebra(gammas: tuple[Tensor, ...],
                            О·: Tensor | None = None,
                            atol: float = 1e-6) -> dict[str, bool | Tensor]:
    """
    Verify that {Оі^Ој, Оі^ОЅ} = 2 О·^ОјОЅ I_4 for all pairs Ој, ОЅ.

    Args:
        gammas: Tuple of 4 gamma matrices.
        О·: Metric tensor. Defaults to diag(1, -1, -1, -1).
        atol: Absolute tolerance for equality.

    Returns:
        Dict with keys:
          - 'passed': True if all pairs satisfy the algebra.
          - 'results': (4, 4) tensor of max deviations per pair.
          - 'max_deviation': maximum absolute deviation across all pairs.
    """
    if О· is None:
        О· = torch.diag(torch.tensor([1, -1, -1, -1], dtype=torch.complex64))

    I4 = torch.eye(4, dtype=torch.complex64)
    results = torch.zeros(4, 4, dtype=torch.float64)

    for Ој in range(4):
        for ОЅ in range(4):
            anticom = clifford_anticommutator(gammas[Ој], gammas[ОЅ])
            expected = 2 * О·[Ој, ОЅ] * I4
            diff = (anticom - expected).abs().max().item()
            results[Ој, ОЅ] = diff

    max_dev = results.max().item()
    return {
        'passed': max_dev < atol,
        'results': results,
        'max_deviation': max_dev,
    }


# в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
#  Complexified Velocity
# в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

def complexified_velocity(X: Tensor, Y: Tensor, Z: Tensor) -> Tensor:
    """
    Compute the в„‚Ві complexified velocity map.

    The mapping is:
        Vв‚Ѓ = X + j В· (-Y)   = X - jY
        Vв‚‚ = Y + j В· (-X)   = Y - jX
        Vв‚ѓ = Z + j В· Z      = Z(1 + j)

    This couples Xв†”Y antisymmetrically and leaves Z self-paired,
    producing the non-isotropic в„‚Ві structure that is the source of
    "divergence sensitivity" in the H-ANS architecture.

    Args:
        X: Tensor of shape (...,), real-valued.
        Y: Tensor of shape (...,), real-valued.
        Z: Tensor of shape (...,), real-valued.

    Returns:
        Complex tensor of shape (..., 3) with Vв‚Ѓ, Vв‚‚, Vв‚ѓ in the last dim.
    """
    # Promote to complex
    X_c = X.to(dtype=torch.complex64)
    Y_c = Y.to(dtype=torch.complex64)
    Z_c = Z.to(dtype=torch.complex64)

    V1 = X_c - 1j * Y_c   # X + j(-Y)
    V2 = Y_c - 1j * X_c   # Y + j(-X)
    V3 = Z_c * (1 + 1j)   # Z + jZ

    return torch.stack([V1, V2, V3], dim=-1)


def complexified_velocity_inverse(V: Tensor) -> tuple[Tensor, Tensor, Tensor]:
    """
    Recover (X, Y, Z) from complexified velocity.

    Given Vв‚Ѓ, Vв‚‚ в€€ в„‚ and Vв‚ѓ в€€ в„‚, the inverse map exists as a linear solve:
        X = (jВ·Vв‚‚ - jВ·Vв‚Ѓ) / (jВІ - 1)  ... simplified:
        X = Re( (Vв‚Ѓ + Vв‚‚) / (1 - j) )  ... checks out actually:
        
    Solving the linear system:
        Vв‚Ѓ = X - jY
        Vв‚‚ = Y - jX
        
    In matrix form:
        [Vв‚Ѓ]   [1  -j] [X]
        [Vв‚‚] = [-j  1] [Y]
        
    det = 1 - (-j)(-j) = 1 - jВІ = 1 + 1 = 2
        
        [X]   (1/2) [ 1   j] [Vв‚Ѓ]
        [Y] = (1/2) [ j   1] [Vв‚‚]
        
    And Vв‚ѓ = Z(1+j) в†’ Z = Vв‚ѓ / (1+j)

    Returns:
        Tuple (X, Y, Z) of real-valued tensors with same shape as V[..., 0].
    """
    V1 = V[..., 0]
    V2 = V[..., 1]
    V3 = V[..., 2]

    # Invert the 2Г—2 system for X, Y
    X = 0.5 * (V1 + 1j * V2).real
    Y = 0.5 * (1j * V1 + V2).real
    Z = (V3 / (1 + 1j)).real

    return X, Y, Z


# в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
#  Branch Superposition Primitives
# в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

def coherent_superposition(amplitudes: Tensor, phases: Tensor) -> Tensor:
    """
    Coherent sum of branch amplitudes: ОЈбµў О±бµў exp(iВ·Оёбµў).

    Args:
        amplitudes: Real tensor of shape (..., B) вЂ” branch magnitudes |О±бµў|.
        phases: Real tensor of shape (..., B) вЂ” branch phases Оёбµў in radians.

    Returns:
        Complex tensor of shape (...,) вЂ” the coherent sum ОЈбµў О±бµў exp(iОёбµў).
    """
    return torch.sum(amplitudes * torch.exp(1j * phases), dim=-1)


def interference_pattern(amplitudes: Tensor, phases: Tensor) -> Tensor:
    """
    Compute the interference |ОЈбµў О±бµў exp(iОёбµў)|ВІ.

    Args:
        amplitudes: Real tensor of shape (..., B).
        phases: Real tensor of shape (..., B).

    Returns:
        Real tensor of shape (...,) вЂ” the squared magnitude of the sum.
    """
    summed = coherent_superposition(amplitudes, phases)
    return (summed * summed.conj()).real


def born_probability(psi: Tensor) -> Tensor:
    """
    Born rule: probability = |П€|ВІ.

    Args:
        psi: Complex tensor of arbitrary shape.

    Returns:
        Real non-negative tensor, same shape as psi.
    """
    return (psi * psi.conj()).real


